def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.2:
            if ratio < 1.7:
                priority = ((ratio - 1.2) ** 3) * 350 + 15
                for x in range(1, 5):
                    priority += np.cos(np.pi * x * ratio) * (4.5 / x)
                if capacity % 5 == 0:
                    priority += 4.1
                elif capacity % 8 == 0:
                    priority += 3.3
                for y in range(1, 4):
                    priority += ((-1) ** (y+1)) * np.exp(-y * ratio) * (y * 1.2)
                if ratio > 1.5:
                    priority += ((ratio - 1.5) ** 2) * 100
            elif ratio < 2.8:
                priority = (ratio - 1.7) * 280 + 55
                for z in range(1, 6):
                    priority += np.log(z + capacity) * ((-1) ** z) / (z + 0.5)
                if capacity % 9 == 0:
                    priority -= 2.3
                if capacity > item * 20:
                    for w in range(2, 8):
                        priority += ((-1) ** w) * np.sqrt(w) * (ratio ** (1/w)) * 1.1
                if priority > 70:
                    priority = 70 + np.sqrt(priority - 69) * 1.7
            else:
                priority = np.inf
        else:
            series_accum = 0.0
            for n in range(1, 12):
                factor = ((-1) ** n) * (ratio ** (n * 1.3)) / (n * 1.1)
                if n % 4 == 0:
                    factor *= 2.1
                series_accum += factor
            priority += abs(series_accum) * 2.1
            if capacity < item * 2:
                priority *= 3.2
            log_diff = np.log(capacity + 5) - np.log(item + 1.7)
            if log_diff > 0:
                priority += 12 / log_diff
            else:
                priority += 40
            mod_list = [2, 3, 5, 7]
            for md in mod_list:
                if capacity % md == 0:
                    priority += md * 0.2
            if ratio < 0.3:
                for m in range(1, 7):
                    term = ((-1)**(m+1)) * (ratio**(m*2.7)) * (m*0.8)
                    if m == 5 and capacity > item * 8:
                        term *= 1.5
                    priority += term
            if capacity > 7 * item:
                priority -= 4.5
            if capacity % 11 == 0 and ratio < 0.6:
                priority -= 1.7
            if capacity > item * 15:
                for q in range(2, 8):
                    sqrt_q = np.sqrt(q * 1.1)
                    power_term = ratio ** (1 / (q + 0.5))
                    sign_term = (-1) ** (q + 1)
                    priority += sqrt_q * power_term * sign_term * (q * 0.4)
            if priority > 65:
                priority = 65 + np.log(priority - 64) * 1.3
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
